#include<bits/stdc++.h>
using namespace std;
const int N=105;
int dp[10005],a[N][N],n,m,ans,t;
int main()
{
    cin>>t>>n>>m;
    for(int i=1;i<=t;i++)
    {
        for(int j=1;j<=n;j++)
        {
            cin>>a[i][j];
        }
    }
    ans=m;
    for(int i=1;i<t;i++)
    {
        memset(dp,0xbf,sizeof(dp));
        dp[ans]=ans;
        for(int j=1;j<=n;j++)
        {
            for(int k=ans;k>=a[i][j];k--)
            {
                dp[k-a[i][j]]=max(dp[k-a[i][j]],dp[k]+a[i+1][j]-a[i][j]);
            }
        }
        int maxx=0;
        for(int j=0;j<=ans;j++)
        {
            maxx=max(maxx,dp[j]);
        }
        ans=maxx;
    }
    cout<<ans;
    return 0;
}
